VALUES
  ('disabled-6f0ba476-moex-00301', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司所有存貨於5月1日的土石流中全數損毀，由於尚未完成4月份之 財務報表，因此必須估計期末存貨損失金額。該公司 4 月期初存貨為 $215,450，4月份進貨$192,530，銷貨收入$542,500。假設公司之平均毛利 率為40%，試問損毀之存貨金額估計應為：', '["$81,480", "$82,480", "$87,480", "$217,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00302', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X1 年 9 月 1 日以$75,000 購得機器一台，估計殘值$10,000，耐 用年限4年，並使用雙倍餘額遞減法提列折舊。在X3年12月31日時， 以$13,000出售該機器。試問出售分錄應包括：', '["借記：「出售損失」$542", "借記：「出售損失」$2,625", "借記：「出售損失」$2,667", "貸記：「出售利得」$13,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00303', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X0年1月1日有面額$1,000，240,000股之普通股股本$240,000,000 ，股本溢價-普通股$354,000,000。保留盈餘$972,000,000。X0年3月1日， 公司以$66,000,000購回30,000股庫藏股。4月1日出售15,000股庫藏股， 得款$34,500,000。5 月 1 日再出售 15,000 股庫藏股，得款$30,000,000，試 問甲公司X0年12月31日應於財務報表顯示之帳面金額，何者正確？', '["股本溢價總額 $352,500,000（貸餘）", "股本溢價-庫藏股 $1,500,000（借餘）", "保留盈餘 $970,500,000（貸餘）", "庫藏股交易損失 $1,500,000（借餘） 30650"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00304', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X1年1 月1 日發行5年期公司債，面額$500,000，票面利率10% ，每年 1 月 1 日及 7 月 1 日付息，當時有效利率 8%。X1 年 7 月 1 日付 息分錄借記「公司債利息」$21,622 及「公司債溢價」$3,378，則該公司 債售價為：', '["$500,000", "$533,780", "$540,550", "$560,720"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00305', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司從事成衣進口買賣，X1 年 12 月 31 日之期末存貨帳帳載餘額原有 $412,000，發現尚有額外資訊如下： ⑴期末存貨帳帳載餘額$412,000中，包括一筆寄銷品$72,000，甲公司為寄 銷人。 ⑵期末存貨帳帳載餘額$412,000中，包括存放於倉庫中之「辦公用品」存 貨$22,000，可供公司管理人員在次年度辦公使用。 ⑶期末存貨帳帳載餘額$412,000中，未包括一筆12月28日目的地交貨， 價值$48,000之進貨。甲公司直到X2年1月2日才收到該筆進貨。 ⑷期末存貨帳帳載餘額$412,000中，包括一筆已受損但尚未記錄減損之存 貨，其原始成本為$38,000，淨變現價值為$10,000。 ⑸期末存貨帳帳載餘額$412,000中，包括一筆承銷品$43,000，甲公司為承 銷人。 試問甲公司 X1 年12 月31 日財務狀況表所列，期末存貨之正確餘額（淨 額）應為：', '["$319,000", "$341,000", "$369,000", "$460,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00306', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司出售電腦產生銷貨收入$12,000，這批電腦提供保證型保固服務，估 計因保固服務而產生之成本為銷貨收入之2%，甲公司應：', '["省略對保固費用之會計處理，因為只有2%", "一律在保固修理工作完成時，認列保固費用，以符合配合原則", "一律將保固費用視為或有負債，附註揭露即可", "一律在銷貨收入產生當期認列保固費用與保固負債"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00307', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X1年度有以下相關資料： ⑴X1年1月1日期初應收帳款餘額$115,000，12月31日期末應收帳款餘 額$100,000 ⑵X1年12月31日公司宣布每股$0.05之股利，當日流通在外股票為 2,800,000股，並於X2年1月31日發放。公司於X0年並未宣布或發放任何 股利 ⑶以$5,000出售帳面金額$7,000之卡車，產生損失$2,000 ⑷支付公司債利息$780,000 ⑸X0年12月31日現金餘額$106,000，X1年12月31日現金餘額$284,000 試問甲公司營業活動現金流量、投資活動現金流量與籌資活動現金流量合 計為：', '["與X1年報導之淨利數相同", "現金流出$582,000", "現金流入$178,000", "現金流入$284,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "998de82ed70f", "answer_pdf_sha1": "6717b96c0f3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00308', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲受贈 A 油畫，非因自己之過失誤認該件油畫為複製品，乃以 5 千
元出賣於乙，同時履行之。10 日後乙以 5 萬元將 A 畫轉賣於丙，銀
貨兩訖；丙於締約時知悉甲誤認 A 畫為複製品而賤售給乙。3 個月
後，甲獲知該畫為當代藝術家之真品，價值 50萬元。試問：
甲得否撤銷與乙間之法律行為，向乙請求返還A畫？（12 分）
甲得否向丙請求返還 A畫？（13 分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00309', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲以家族資金從事投資，為 A 地之所有人，於民國（下同）95 年突
然死亡，其妻乙與 16 歲之女兒丙為繼承人。經家族會議決議，由乙
為丙辦理拋棄繼承；且除甲之弟丁外，其餘順位之繼承人均拋棄繼承，
由乙與丁成為甲之繼承人，處理甲遺留之債權債務。乙丁二人於 96
年就 A地辦理繼承登記，共同繼承該地。試問：
乙為丙辦理拋棄繼承之效力如何？（10分）
若丙於100年知悉上述拋棄繼承情事，於112年對丁主張繼承回復請
求權，並訴請丁將丙對A地之應繼分為回復之登記，丁對於丙之請求
則均主張消滅時效之抗辯，丙、丁各自之主張是否有理由？（15分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00310', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲向乙購買充電電池一組，惟乙遲不交貨，甲遂向乙發出催告，請求乙即 時交貨。該催告之性質為何？', '["意思表示", "意思通知", "觀念通知", "感情表示"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
